SET
  @ID_1472c9ad = '557E8C46-9DB3-4500-8FFB-6B6930B30BE0' EXEC [${flyway:defaultSchema}].spUpdateTemplateContent @TemplateID = @TemplateID_1472c9ad,
  @TypeID = @TypeID_1472c9ad,
  @TemplateText = @TemplateText_1472c9ad,
  @Priority = @Priority_1472c9ad,
  @IsActive = @IsActive_1472c9ad,
  @ID = @ID_1472c9ad;

